pub async fn get_all_users(pool: &sqlx::PgPool) -> Result<Vec<GetAllUsersRow>, sqlx::Error> {
    sqlx::query_as!(GetAllUsersRow, "SELECT id, name FROM users")
        .fetch_all(pool)
        .await
}

